#include <WiFi.h>
#include <esp_http_client.h>

#define WIFI_SSID "your_ssid"
#define WIFI_PASSWORD "your_password"

char *server_url = "http://example.com/firmware.bin";
esp_err_t http_status;

void http_download(char *url, char *filename) {
    esp_http_client_config_t config = {
        .url = url,
        .event_handler = {
            NULL,
            NULL,
            NULL,
            NULL
        }
    };
    esp_http_client_handle_t client = esp_http_client_init(&config);
    if (esp_http_client_perform(client) == ESP_OK) {
        http_status = esp_http_client_get_response_code(client);
        if (http_status != 200) {
            Serial.println("Failed to download firmware");
            return;
        }
        char *response_data = esp_http_client_get_response_data(client);
        int data_len = esp_http_client_get_header_field_value(client, "Content-Length");
        const char *filename_out = "/flash/" + String(filename);

        // Write response data to file
        FILE *fp = fopen(filename_out, "wb");
        fwrite(response_data, 1, data_len, fp);
        fclose(fp);

        Serial.println("Firmware downloaded and saved successfully");
    } else {
        Serial.println("Failed to download firmware");
    }
    esp_http_client_cleanup(client);
}

void setup() {
    Serial.begin(115200);
    WiFi.begin(WIFI_SSID, WIFI_PASSWORD);
    while (WiFi.status() != WL_CONNECTED) {
        delay(1000);
        Serial.println("Connecting to WiFi..");
    }

    Serial.println("Connected to the network");

    http_download(server_url, "firmware.bin");

    // Save downloaded firmware to flash memory
    esp_flash_erase(ESP_PARTITION_APP);

    const char *filename_out = "/flash/firmware.bin";
    FILE *fp = fopen(filename_out, "rb");
    fseek(fp, 0, SEEK_END);
    int size = ftell(fp);
    rewind(fp);
    char buffer[size];
    fread(buffer, 1, size, fp);
    fclose(fp);

    // Reboot to apply the update
    esp_restart();
}

